{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 한다.",
        "condition": "스모크 테스트 통과",
        "source_certainty": "confirmed"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "status": "rejected",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "internal stretch goal only",
        "note": "Doyun이 스모크 테스트 선통과 필요성을 이유로 반대했으며 최종 릴리스 결정은 아님.",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps를 목요일까지 가능하면 검토한다.",
        "reason": "소유자가 지정되지 않았다.",
        "source_certainty": "confirmed"
      },
      {
        "item": "Hara의 generated tarball path 확인 기한",
        "reason": "Minjun의 스모크 결과 공유 이후 확인한다고만 되어 있으며 정확한 마감은 없다.",
        "source_certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README install steps가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "unassigned_non_decision",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부",
      "Doyun의 금요일 12:00 KST action_items.md failure triage note 작성 여부",
      "스모크 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 진행 가능 여부",
      "packageName mismatch 발생 시 패키지 설정 확인 결과",
      "Minjun 결과 공유 이후 Hara의 generated tarball path 확인 결과",
      "README install steps 검토 소유자 지정 여부",
      "최종 릴리스 승인 권한자 결정 여부",
      "릴리스 노트에 수요일 내부 stretch goal을 언급할지 여부"
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "언급된 고객명이 없으므로 고객을 생성하지 않는다.",
    "budget": "예산 정보가 없으므로 예산을 생성하지 않는다.",
    "security": "보안 사고가 언급되지 않았으므로 보안 이슈를 생성하지 않는다.",
    "outage": "프로덕션 장애가 언급되지 않았으므로 장애 사실을 생성하지 않는다.",
    "legal": "법무 승인 요구사항이 언급되지 않았으므로 법무 조건을 생성하지 않는다.",
    "owner": "명시된 owner만 사용하고, README 검토처럼 owner가 없는 항목은 null로 둔다.",
    "deadline": "명시된 마감만 사용하고, Hara 항목처럼 정확한 기한이 없으면 null로 둔다.",
    "reference_outputs": "golden/reference output을 사용하거나 추론하지 않는다."
  }
}
